import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Google Cloud クォータ確認: G3/Claude残量 | opencode-mystatus","description":"Google Cloudのクォータ確認方法を学びます。G3 Pro/Image/Flash、Claudeの残量とリセット時間を一括確認できます。","frontmatter":{"title":"Google Cloud クォータ確認: G3/Claude残量 | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloudクォータクエリ：G3 Pro/Image/FlashとClaude","description":"Google Cloudのクォータ確認方法を学びます。G3 Pro/Image/Flash、Claudeの残量とリセット時間を一括確認できます。","tags":["Google Cloud","Antigravity","クォータクエリ"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"ja/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),i={name:"ja/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function s(d,a,n,r,u,g){return o(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="google-cloudクォータクエリ-g3-pro-image-flashとclaude" tabindex="-1">Google Cloudクォータクエリ：G3 Pro/Image/FlashとClaude <a class="header-anchor" href="#google-cloudクォータクエリ-g3-pro-image-flashとclaude" aria-label="Permalink to &quot;Google Cloudクォータクエリ：G3 Pro/Image/FlashとClaude&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><ul><li>Google Cloud Antigravityアカウントの4つのモデルクォータを確認する</li><li>各モデルのリセット時間と残りパーセンテージを理解する</li><li>複数のGoogle Cloudアカウントのクォータ使用を管理する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>Google Cloud Antigravityは複数のモデル（G3 Pro、G3 Image、G3 Flash、Claude）を提供しており、各モデルには独立したクォータとリセット時間があります。以下が必要です：</p><ul><li>各モデルの状態を確認するために各々Google Cloudコンソールにログイン</li><li>残りクォータとリセット時間を手動で計算</li><li>複数アカウントを管理するとさらに混乱する</li></ul><h2 id="いつ使用するか" tabindex="-1">いつ使用するか <a class="header-anchor" href="#いつ使用するか" aria-label="Permalink to &quot;いつ使用するか&quot;">​</a></h2><p>以下の時に使用します：</p><ul><li>すべてのGoogle Cloudモデルの残りクォータを素早く知りたい時</li><li>異なるモデル間の使用分配を計画したい時</li><li>複数のGoogle Cloudアカウントを統一管理したい時</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提チェック</p><ol><li><strong>mystatusプラグインがインストールされていること</strong>：<a href="/docs/opencodedocs/ja/vbgate/opencode-mystatus/start/quick-start/">クイックスタート</a>を参照</li><li><strong>Google Cloud認証が設定されていること</strong>：先に <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> プラグインをインストールしてOAuth認証を完了</li><li><strong>認証ファイルが存在すること</strong>：<code>~/.config/opencode/antigravity-accounts.json</code> に少なくとも1つのアカウントが含まれている</li></ol></div><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>Google Cloud AntigravityはOAuthメカニズムで認証し、各アカウントには独立したRefresh Tokenがあります。mystatusプラグインは以下を行います：</p><ol><li><code>antigravity-accounts.json</code> を読み取り、すべての設定済みアカウントを取得</li><li>Refresh Tokenを使用してAccess Tokenをリフレッシュ</li><li>Google Cloud APIを呼び出してすべてのモデルのクォータを取得</li><li>アカウント別に4つのモデルのクォータとリセット時間を表示</li></ol><h2 id="google-cloudがサポートするモデル" tabindex="-1">Google Cloudがサポートするモデル <a class="header-anchor" href="#google-cloudがサポートするモデル" aria-label="Permalink to &quot;Google Cloudがサポートするモデル&quot;">​</a></h2><p>mystatusは以下の4つのモデルのクォータを表示します：</p><table tabindex="0"><thead><tr><th>表示名</th><th>モデルKey（メイン/サブ）</th><th>説明</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro高性能バージョン</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro画像生成</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash高速バージョン</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5モデル</td></tr></tbody></table><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-クエリコマンドを実行" tabindex="-1">ステップ1：クエリコマンドを実行 <a class="header-anchor" href="#ステップ1-クエリコマンドを実行" aria-label="Permalink to &quot;ステップ1：クエリコマンドを実行&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>期待される結果</strong>： すべての設定済みプラットフォームのクォータ情報が含まれ、Google Cloud部分には以下のような内容が表示されます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="ステップ2-出力形式を理解する" tabindex="-1">ステップ2：出力形式を理解する <a class="header-anchor" href="#ステップ2-出力形式を理解する" aria-label="Permalink to &quot;ステップ2：出力形式を理解する&quot;">​</a></h3><p>各行の形式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[モデル名] [リセット時間] [プログレスバー] [残りパーセンテージ]</span></span></code></pre></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下を完了したか確認してください：</p><ul><li>[ ] <code>/mystatus</code> を実行した後、Google Cloudクォータ情報が表示される</li><li>[ ] 4つのモデルの名前とリセット時間を理解できる</li><li>[ ] プログレスバーと残りパーセンテージを識別できる</li><li>[ ] 複数アカウントがある場合、すべてのアカウントのクォータが表示される</li></ul><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="問題1-google-cloudクォータが見られない" tabindex="-1">問題1：Google Cloudクォータが見られない <a class="header-anchor" href="#問題1-google-cloudクォータが見られない" aria-label="Permalink to &quot;問題1：Google Cloudクォータが見られない&quot;">​</a></h3><p><strong>可能な原因</strong>：</p><ul><li>opencode-antigravity-authプラグインがインストールされていない</li><li>Google OAuth認証が完了していない</li><li><code>antigravity-accounts.json</code> ファイルが存在しないか空</li></ul><p><strong>解決方法</strong>：</p><ol><li>opencode-antigravity-authプラグインをインストール</li><li>GitHubリポジトリの説明に従って認証を完了</li><li><code>/mystatus</code> を再度実行</li></ol><h3 id="問題2-あるアカウントでエラーが表示される" tabindex="-1">問題2：あるアカウントでエラーが表示される <a class="header-anchor" href="#問題2-あるアカウントでエラーが表示される" aria-label="Permalink to &quot;問題2：あるアカウントでエラーが表示される&quot;">​</a></h3><p><strong>可能な原因</strong>：</p><ul><li>Refresh Tokenが期限切れ</li><li>projectIdがない</li></ul><p><strong>解決方法</strong>：</p><ol><li>opencode-antigravity-authプラグインを使用して再度そのアカウントを認証</li><li>認証プロセスで正しくプロジェクトIDが設定されていることを確認</li></ol><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><ul><li>Google Cloud Antigravityは4つのモデルをサポート：G3 Pro、G3 Image、G3 Flash、Claude</li><li>各モデルには独立したクォータとリセット時間がある</li><li>複数アカウント管理をサポートし、各アカウントを個別に表示</li><li>使用率が80%を超えると警告表示が表示される</li></ul><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../advanced/google-setup/">Google Cloud高度な設定：複数アカウントとモデル管理</a></strong> を学びます。</p><p>学べること：</p><ul><li>複数のGoogle Cloudアカウントを追加・管理する方法</li><li>4つのモデルのマッピング関係を理解する</li><li>projectIdとmanagedProjectIdの違い</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>モデル設定</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>アカウントクエリロジック</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Tokenリフレッシュ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>クォータ抽出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>出力フォーマット</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr></tbody></table></details>`,46)])])}const p=e(i,[["render",s]]);export{c as __pageData,p as default};
